class Solution {
public:
    int findMinimumOperations(string s1, string s2, string s3) {
        int min_len = min({s1.length(), s2.length(), s3.length()});
        int common_len = 0;
        while (common_len < min_len && s1[common_len] == s2[common_len] && s1[common_len] == s3[common_len]) {
            common_len++;
        }
        if (common_len == 0) return -1;
        return s1.length() + s2.length() + s3.length() - 3 * common_len;
    }
};
efficiency: HIGH
time complexity: O(n)
space complexity: O(1)
energy implications: LOW
explanation: The solution iterates through the input strings from the start, counting the common prefix length. It then calculates the minimum number of operations required to make the strings equal by deleting characters from the end. If there's no common prefix, it returns -1.
